SELECT *
FROM notices
WHERE 
ORDER BY pinned DESC, created_at DESC, notice_id DESC
LIMIT #{limit}
OFFSET #{offset}

SELECT *
FROM notices

    deleted = 0

        AND (title LIKE CONCAT('%', #{keyword}, '%') OR content LIKE CONCAT('%', #{keyword}, '%'))


        AND published = #{published}


ORDER BY pinned DESC, created_at DESC, notice_id DESC
LIMIT #{limit}
OFFSET #{offset}
